async function compressHistory(messages) {
  const toCompress = messages.slice(0, -5);
  const toKeep = messages.slice(-5);
  const summaryResponse = await client.messages.create({
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 500,
    messages: [{ role: 'user', content:
      `Summarize the key actions taken, findings, and decisions from this conversation:\n${JSON.stringify(toCompress, null, 2)}` }]
  });
  const summary = summaryResponse.content[0].text;
  return [
    { role: 'user', content: `[Session summary]: ${summary}` },
    { role: 'assistant', content: 'Understood. Continuing from where we left off.' },
    ...toKeep
  ];
}
