async function buildMemoryInjection(userId) {
  const [prefs, projects, errors] = await Promise.all([
    db.agentMemory.findMany({ where: { userId, type: 'preference' }, orderBy: { updatedAt: 'desc' }, take: 5 }),
    db.agentMemory.findMany({ where: { userId, type: 'decision', key: { startsWith: 'project:' } }, take: 3 }),
    db.agentMemory.findMany({ where: { userId, type: 'error', createdAt: { gt: new Date(Date.now() - 30*24*60*60*1000) } }, take: 3 })
  ]);
  return `
User preferences:
${prefs.map(p => `- ${p.content}`).join('\n')}

Active projects:
${projects.map(p => `- ${p.content}`).join('\n')}

Known issues to avoid:
${errors.map(e => `- ${e.content}`).join('\n')}
`.trim();
}
