async function evaluateFaithfulness(question, chunks, answer) {
  // Step 1: Extract claims
  const claimsResponse = await client.messages.create({ model: 'claude-haiku-4-5-20251001', max_tokens: 300,
    messages: [{ role: 'user', content: `List each factual claim in this answer as bullet points (be specific):\n${answer}` }] });
  const claims = claimsResponse.content[0].text.split('\n').filter(l => l.startsWith('-'));

  // Step 2: Verify each claim
  const context = chunks.map(c => c.content).join('\n---\n');
  let verified = 0;
  const hallucinations = [];
  for (const claim of claims) {
    const check = await client.messages.create({ model: 'claude-haiku-4-5-20251001', max_tokens: 50,
      messages: [{ role: 'user', content: `Does the following claim appear in these sources? Answer SUPPORTED or UNSUPPORTED.\nClaim: ${claim}\nSources: ${context}` }] });
    if (check.content[0].text.includes('SUPPORTED')) verified++;
    else hallucinations.push(claim);
  }
  return { score: verified / claims.length, total: claims.length, verified, hallucinations };
}
